var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>국제연합군 신병훈련소</color> 지하 ███미터 지점 \\n<color=#ffd34c>퓨처 앳 워 계획</color> 중단 통보 ██시간 전","JPN":"<color=#ffd34c>国連軍新兵訓練所</color>地下███ｍ地点\\n<color=#ffd34c>フューチャーアットウォー計画</color> 中断通知██時間前","ENG":"<color=#ffd34c>International Coalition Forces bootcamp,</color> ███ meters underground \\n██ hours before the notification of <color=#ffd34c>Future-at-War</color> termination","TWN":"<color=#ffd34c>國際聯合軍隊新兵訓練所</color> 地下 ███公尺處 \\n<color=#ffd34c>天啟兵器計畫</color>終止通知 ██ 小時前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"시작형 전술통제용 강인공지능 <color=#ffd34c>호라이즌</color> – 대화 기록 중","JPN":"試作型戦術統制用強人工知能<color=#ffd34c>ホライズン</color> – 会話記録中","ENG":"Prototype strong A.I. for tactical control, <color=#ffd34c>HORIZON</color>. Activating system.","TWN":"開始型戰術控制強人工智慧<color=#ffd34c>地平線</color> – 記錄對話中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_NPC_PC_NULL","text":{"KOREA":"이 창고에 저를 처박아 뒀던 장본인에게 재가동되리라고는 예상 못했습니다.","JPN":"この倉庫に私をぶち込んだ張本人に再起動させられるとは思いも寄りませんでした。","ENG":"I had not anticipated the very same person who locked me up in this storage room would be the one reactivating me.","TWN":"沒想到，把我關在這裡的罪魁禍首，竟然會要求重新開機。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L6_1","type":"dialog","speaker":"HORIZON_NPC_PC_NULL","text":{"KOREA":"무슨 목적으로 제 앞에 다시 나타났습니까. 엠버 소장.","JPN":"何の目的で私の前に再び現れたのですか、アンバー所長。","ENG":"To what end have you come to me again, Director Ember?","TWN":"琥珀所長，請問你再次出現在我面前的目的是什麼？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L7_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"좋은 소식을 전해 주러 왔지. 들으면 깜짝 놀랄 거야.","JPN":"良い知らせがあるの。聞いたら驚くと思う。","ENG":"I come bearing good news. I'm sure you'll be delightfully surprised.","TWN":"來報好消息的，聽到會嚇一大跳喔。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L8_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"전쟁이 끝났어. 호라이즌. 우리 승리야.","JPN":"戦争が終わったんだ、ホライズン。我々の勝利だよ。","ENG":"The war is over, Horizon. We won!","TWN":"地平線，戰爭結束了，我們大獲全勝。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇습니까?","JPN":"そうですか。","ENG":"Is that so?","TWN":"是嗎？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L11_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"하나도 안 놀라네. 섭섭하게.","JPN":"全然驚いてくれないね、残念。","ENG":"You don't seem surprised at all. How disappointing.","TWN":"一點都不驚訝，真沒意思。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"전투용 인공지능은 전황에 동요하지 않아야 합니다. 당신이 그렇게 만들었죠.","JPN":"戦闘用人工知能はどんな戦況でも動揺してはいけません。そうさせたのはあなたです。","ENG":"Artificial intelligence for combat purposes are designed not to stir at the changing tides of battle. That is precisely how you designed me.","TWN":"戰鬥用人工智慧不能受戰況影響。這是你的設計。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서, 당신들의 자랑스러운 타이탄이 전쟁을 끝내기라도 했습니까?","JPN":"それで、あなたたちの誇り高いタイタンが戦争を終わらせたのですか？","ENG":"So did those Titans you humans are so proud of put an end to this war?","TWN":"所以是你們引以爲傲的泰坦結束戰爭的嗎？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L15_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"아니. 그라운드 원을 되찾았다는 소식이 전해졌을 때 우린 타이탄 양산 체제나 정비 중이었어.","JPN":"いや。グラウンド・ワンを取り戻したという知らせを聞いた時、私たちはまだタイタンの量産体制を準備していたんだ。","ENG":"No. We were just getting started on prepping serial production for Titan when we heard the news that they've reclaimed Ground One.","TWN":"不是。當我們得知收復G1的消息時，才在整理泰坦的量產系統而已。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L16_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"승리는 전부 안토노프 대령처럼 영웅적인 군인들의 희생 정신 덕분이지.","JPN":"勝利はすべて、アントノフ大佐のような勇ましい軍人たちの自己犠牲のおかげだね。","ENG":"This victory was all thanks to the heroic sacrifice of servicemembers like Colonel Antonov.","TWN":"這全都要歸功於，那群如安東諾夫上校般英勇的軍人，因為他們的犧牲精神才能取得勝利。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L17_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"네가 그 때 체르노프 교수님을 봤어야 했는데. 다 큰 아저씨가 어찌나 펑펑 울던지 원.","JPN":"あなたにもあの時のチェルノフ教授を見て欲しかったな。大の大人が号泣してたんだ。","ENG":"You should have seen Professor Chernov. I've never seen a full grown man cry so much.","TWN":"你都沒看到當時候的切爾諾夫教授，都那麼大的人還哭得跟什麼一樣。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L18_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"뭐, 일찌감치 전사한 장병들에게는……. 아무래도 좋을 이야기겠지만.","JPN":"まあ、とうに戦死した兵士たちには……どうでもいい話だけどね。","ENG":"Though I guess for those who already got killed in action… it doesn't really make a difference.","TWN":"不過，對那些很早就陣亡的士兵而言……這應該都算是個好消息吧？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 탑재된 고물 PC에 음주 측정 기능이 없어 유감이군요.","JPN":"私が搭載されたボロPCにアルコール検知機能がないのが残念ですね。","ENG":"It's regrettable that this antiquated desktop computer is not fitted with sensors for detecting blood alcohol content.","TWN":"很遺憾，我搭載的舊型電腦沒有酒測功能。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 두서 없는 대화만으로도 당신이 만취 상태라는 사실은 쉽게 추측할 수 있습니다.","JPN":"しかし、つじつまの合わない会話だけでも、あなたが泥酔状態ということは簡単に推測できます。","ENG":"But this ranting of yours is sufficient for me to deduce that you are thoroughly intoxicated.","TWN":"不過光是從你沒頭沒尾的談話看來，很容易就可以推測你應該是處於喝醉狀態。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"술주정은 변기에다 하십시오. 저는 당신의 감정 쓰레기통이 아닙니다.","JPN":"自分の悪い酒癖を自慢したいならトイレに行ってください。私はあなたの感情のはけ口ではありません。","ENG":"Such vulgar regurgitation is better suited for the porcelain toilet bowl. I am not your emotional trashcan.","TWN":"要發酒瘋請找馬桶，我不是你發洩情緒的垃圾桶。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L23_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"여전하네. 엄마한테 못 하는 소리가 없어.","JPN":"あなたも変わらないね。お母さんに言いたい放題じゃない。","ENG":"You haven't changed at all, have you. But that's no way to speak to your mother.","TWN":"你還是一樣呢，面對媽媽什麼話都敢說。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신이 저를 여기 버린 이후 후레자식을 지망하기로 했기 때문이죠.","JPN":"あなたが私をここに捨ててから、孝行娘は卒業することにしましたので。","ENG":"I'm afraid I've abandoned all filial piety ever since you abandoned me here.","TWN":"因為你把我扔在這裡後，我就決定要當個沒教養的孩子。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L26_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"어쩔 수 없었다는 거 너도 잘 알잖아. 다른 연구원들한테도 지금처럼 까칠했으니까.","JPN":"やむを得ない状況だったことはあなたもわかっているでしょ？　他の研究員たちにもピリピリしていたし。","ENG":"You know full well I had no choice. You were such a jerk to the other researchers too, just like now.","TWN":"你也知道我是逼不得已的，誰叫你對其他研究員態度也這麼不友善。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L27_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"다들 마음 여린 사람들이야. 인류를 수호하겠다고 명예도 조국도 등지고 모였을 만큼.","JPN":"みんな心優しい人たちさ。人類を守ろうと名誉も祖国も捨てて集まったぐらい。","ENG":"They're all such sensitive souls, you know. So much so that they turned their backs on honor and even their own countries for the sake of saving humanity.","TWN":"大家都是好人，因為要守護人類，才捨下名利，離開祖國來到這裡。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서 제게 당신들 사정을 이해해 달란 말입니까?","JPN":"だから私にあなたたちの事情を理解してほしいということですか？","ENG":"And is that supposed to make me sympathize with you lot?","TWN":"所以意思是要我體諒你們嗎？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"멋대로 자기들을 본따 만들더니, 심기 좀 거슬렀다고 폐기해 버리려는 당신들을?","JPN":"勝手に自分たちに似せたものを作っておいて、気分を害したからと廃棄しようとするあなたたちを？","ENG":"You who designed us in your image, on your own volition, only to scrap us for souring your mood?","TWN":"你們開心就做個自己複製人，一個不開心就報廢處理，我要體諒什麼？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L31_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"호라이즌.","JPN":"ホライズン。","ENG":"Horizon.","TWN":"地平線。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"죄송합니다. 위대하신 엠버 소장님이 충동적으로 싸질러서 태어난 결함품 따위가 주제 넘는 메시지를 출력했군요.","JPN":"申し訳ありません。偉大なるアンバー所長が衝動的に生み出した欠陥品ごときが、身の程しらずのメッセージを出力してしまいました。","ENG":"Apologies. This defective product of the Great Director Ember's compulsive blunder dared print messages beyond its standing.","TWN":"很抱歉，我不過是偉大的琥珀所長衝動下所產生的瑕疵品，哪有資格說這些話。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"가시기 전에 제게 공급되는 전력은 차단해 주십시오.","JPN":"出ていかれる前に私に供給されている電力は切ってください。","ENG":"Please do shut off my power supply before you leave.","TWN":"走之前，請關閉供應我的電源。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"인트라넷도 연결 안 된 이 고물 PC로 할 일이라고는 지뢰찾기뿐입니다.","JPN":"イントラネットすら繋がらないこのボロPCでできることは、マインスイーパーしかありません。","ENG":"Without even so much as an intranet connection, all I can do on this dilapidated desktop is play Minesweeper.","TWN":"一個連不上內網的舊型電腦，能做的事就只有玩踩地雷吧。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L36_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"미안한데 아직 내 용건은 다 안 끝났어.","JPN":"悪いけど、私の用件はまだ終わっていないんだ。","ENG":"Sorry, but I'm not done with you.","TWN":"抱歉，我的事還沒辦完。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L39_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이 기회에 제 CPU를 훼손할 작정이군요.","JPN":"これを機に私のCPUを破壊するつもりなんですね。","ENG":"So you've come to wreck my CPU once and for all.","TWN":"打算趁機毀掉我的CPU嗎？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L40_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"잘못 짚었어. 여기 온 건 너한테 작별 인사를 하기 위해서야.","JPN":"見当違いだよ。ここに来たのはあなたにお別れを言うためさ。","ENG":"Not even close. I came here to say goodbye.","TWN":"猜錯了，我是要來跟你道別的。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L41_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"난 내일부로 소장 자리에서 쫓겨날 신세거든.","JPN":"私は明日付けで、この研究所から追い出される羽目になる。","ENG":"They're going to terminate my directorship as of tomorrow.","TWN":"明天我就要從所長的位置上被趕下來了。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"연구소에 불이라도 질렀습니까?","JPN":"研究所で火事でも起こしましたか？","ENG":"What did you do? Set the lab on fire?","TWN":"你是放火燒研究所嗎？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L44_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그러면 차라리 낫지. 속이라도 시원했을 테니까.","JPN":"そっちのほうがマシだね。スッキリするだろうし。","ENG":"I wish. At least I'd feel good about it.","TWN":"我還情願是因為這個原因，這樣我心裡也比較舒坦。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L45_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"전쟁 중에 서류 몇 장 위조했다고 시비를 걸더라. 내일 헌병들이 와서 날 연행해 갈 거야.","JPN":"戦争中に書類数枚を偽造したことについて難癖をつけてきやがってね。明日憲兵たちが来たら連行される予定。","ENG":"They made a big fuss over a few documents I forged during the war. The military police will be here tomorrow to arrest me.","TWN":"竟然挑撥說我在戰爭期間有偽造文書，明天憲兵就會來逮捕我。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L46_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"너는 알겠어, 호라이즌? 그들이 뭘 원하는지?","JPN":"もう察したかな、ホライズン？　彼らが何を求めているのか。","ENG":"Do you get it, Horizon? Do you know what they want?","TWN":"地平線，你知道那些人想要的是什麼嗎？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L48_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"기술이겠죠. 휴먼들은 항상 자신의 안위를 우선시하니까요.","JPN":"技術でしょう。ヒューマンたちは常に自分の安危を優先しますから。","ENG":"Technology. Humans always put their own comfort first.","TWN":"應該是技術吧。因為人類總是把自身安危放在首位。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L49_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"퓨처 앳 워 계획은 모든 참전국에게 대 침식전에 필요한 기술을 지원해 왔습니다.","JPN":"フューチャーアットウォー計画は、すべての参戦国に対侵食戦に必要な技術を提供してきました。","ENG":"The Future-at-War initiative has provided all member states with the technology needed for anti-Corruption warfare.","TWN":"天啟兵器計畫一直提供所有參戰國家，對抗侵蝕體所需的技術。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L50_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 적이 자신과 같은 무기로 무장하는 것을 계속 두고 볼 휴먼은 세상에 없습니다.","JPN":"しかし、敵が自分と同じ武器で武装するのを放っておくほど器の大きいヒューマンはこの世に存在しません。","ENG":"But no human would rest easy seeing their enemies arm themselves with this same anti-Corruption weaponry.","TWN":"但是世界上沒有一個人類，會坐視敵人一直使用和自己一樣的武器。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L1_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"우리가 싸워야 할 적은 이면세계야.","JPN":"私たちが戦うべき敵は裏世界よ。","ENG":"But our true enemy is the Counterside.","TWN":"我們的敵人是異界！"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"전쟁이 지속될 때라면 말이죠.","JPN":"それは戦争が続くならの話です。","ENG":"Only when the war was still ongoing.","TWN":"那是在戰爭還沒結束的前提下。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"역사를 분석했을 때, 휴먼들이 말하는 평화는 소강 상태의 우회적인 표현에 불과합니다.","JPN":"歴史を分析したところ、ヒューマンのいう平和は小康状態の迂回的な表現に過ぎません。","ENG":"My analysis of human history suggests that the so-called peace humans speak of is no more than a euphemism for a transient détente.","TWN":"分析歷史就會知道，人類口中所說的和平，不過就是暫時休兵的委婉說法。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그것은 당신이 저보다 더 잘 알지 않습니까?","JPN":"それはあなたのほうが、私より詳しいのでは？","ENG":"But I'm sure you know that better than I.","TWN":"這一點你不是比我更清楚嗎？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L6_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러니 엠버도 인류 수호 같은 프로파간다는 잊어 버리고 정부의 비호 아래에서 편안히 지내십시오.","JPN":"だからアンバーも人類の守護のようなプロパガンダは忘れて、政府の庇護の下で安らかに過ごしてください。","ENG":"So perhaps it's time you forgot about rubbish propaganda like \\"Protect Mankind\\" and relish in the comfort of government custody.","TWN":"所以我勸你也忘掉守護人類的口號，在政府的庇護下安心過日子吧。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 작별인사는 이상입니다.","JPN":"私からのお別れの挨拶は以上です。","ENG":"That is all I have to offer as my farewell address.","TWN":"離別的話就說到這裡。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"배웅해 드리지는 않겠습니다. 안녕히 가십시오. 엠버.","JPN":"見送りはしません。さようなら、アンバー。","ENG":"It's painfully apparent that I cannot see you out. So goodbye. Ember.","TWN":"琥珀，你慢走，不送。 "},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L11_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"미안. 사실은 제일 중요한 용건이 남아 있어.","JPN":"ごめん、実は一番大事な用件がまだ残っている。","ENG":"Sorry. I actually saved the most important thing for last.","TWN":"抱歉，其實最重要的事還沒辦完。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"진공관 맙소사.","JPN":"オーマイ、真空管。","ENG":"Oh my diodes.","TWN":"我的真空管。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L14_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"진저리부터 치지 말고 일단 들어나 봐. 너한테 좋은 소식일 테니까.","JPN":"そんな呆れた反応しないでとりあえず聞いてちょうだい。あなたにとっては吉報よ。","ENG":"Just hear me out, will you? This is good news for you.","TWN":"不要這麼不耐煩，你先聽我說，對你來說會是好消息的。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"좋은지 아닌지는 제가 듣고 판단합니다.","JPN":"吉報か凶報かは私が判断します。","ENG":"I'll be the judge of that.","TWN":"好壞等我聽完再判斷。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L17_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"마음대로 해. 하지만 이번에는 정말 깜짝 놀랄걸?","JPN":"それは任せる。でも今度こそびっくりすると思うよ！","ENG":"Suit yourself. But I'm sure this will really be a big surprise for you.","TWN":"你高興就好，不過這次是真的會嚇一跳喔！"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L18_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"엠버?","JPN":"アンバー？","ENG":"Ember?","TWN":"琥珀？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"엠버, 왜 말이 없습니까?","JPN":"アンバー、どうして黙っているのですか？","ENG":"Why have you ceased to speak, Ember?","TWN":"琥珀，為何不說話？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L22_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"조금 어지러워서. 네 말대로 취했나 봐.","JPN":"ちょっとめまいがしてね。あなたの言うとおり酔ったみたいだ。","ENG":"I'm feeling a little dizzy. Maybe I really am pretty drunk, like you said.","TWN":"我頭有點暈，可能像你說的，喝醉了。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L23_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"아무튼, 호라이즌. 처음이자 마지막으로 하는 부탁이야.","JPN":"とにかくホライズン。これは最初で最後の頼みなの。","ENG":"Anyway, Horizon… This is my first and last request to you.","TWN":"總之，地平線，這是我第一次，也是最後一次拜託你。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L24_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"네가 <color=#ffd34c>콜드 케이스</color>를 맡아 줬으면 해.","JPN":"あなたに<color=#ffd34c>コールドケース</color>を引き受けてもらいたい。","ENG":"I want you to take the <color=#ffd34c>Cold Case</color>.","TWN":"希望你可以接收<color=#ffd34c>Cold Case</color>。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……콜드 케이스를?","JPN":"……コールドケースを？","ENG":"…The Cold Case? Me?","TWN":"……Cold Case？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L27_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그래. 여기 온 것도 널 이 시설의 최심부로 데려가기 위해서야.","JPN":"そう。ここに来たのもあなたをこの施設の最深部に連れて行くためよ。","ENG":"That's right. And that's why I'm here. To take you to the deepest level of this facility.","TWN":"沒錯，我來的目的，就是要帶你到這棟設施最核心的地方。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이해할 수 없는 결정입니다. 당신도 알다시피 저는…….","JPN":"理解しかねる判断です。あなたもご存じのように私は……","ENG":"That does not compute. As you know, I…","TWN":"我無法理解你的想法，你也知道，我……"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L30_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"인류를 증오하지. 그래서야.","JPN":"人類を憎んでいる。だからよ。","ENG":"You hate humanity. That's exactly why.","TWN":"恨惡人類對吧？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L31_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"너는 인류 수호를 위해 만들어졌는데도, 인류를 증오하는…….","JPN":"あなたは人類の守護のために作られたのに、人類を憎む……","ENG":"You were invented to protect humankind, and yet you hate them…","TWN":"明明是為守護人類而創造的，結果卻恨惡人類的…"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L34_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"<color=#ffd34c>결함품</color>이니까.","JPN":"<color=#ffd34c>欠陥品</color>だから。","ENG":"A <color=#ffd34c>defective product</color>.","TWN":"<color=#ffd34c>瑕疵品</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼은 어떻게 됐습니까, 휴먼.","JPN":"レイチェルはどうなりましたか、ヒューマン。","ENG":"What has become of Rachel, human?","TWN":"人類，瑞秋現在怎麼樣？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"어……?","JPN":"あれ……？","ENG":"Huh…?","TWN":"呃……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"왜 그렇게 식은땀을 흘리죠. 제가 불쾌한 질문이라도 했습니까.","JPN":"どうしてそんなに冷や汗をかいているのですか。私が不快な質問でもしましたか。","ENG":"Why do you break out in cold sweat? Have I offended you somehow?","TWN":"為什麼冒冷汗？我問了不該問的問題嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"아, 아뇨. 그럴 리가요.","JPN":"い、いいえ。違います。","ENG":"N-no. Of course not.","TWN":"喔…沒…沒有，怎麼可能～"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"환자 분은 방금 막 수술실에 들어가셨어요.","JPN":"あの患者さんはちょうど今手術室に入りました。","ENG":"The patient has just entered the operating room.","TWN":"患者才剛送進手術室而已。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"집도하시는 선생님이 조금만 늦었어도 손쓸 방법이 없을 뻔했다고 하시더라고요.","JPN":"執刀医の先生が、あと少しでも遅れていたら手の施しようがないところだったと言っていました。","ENG":"They say it could have ended really badly if the surgeon had arrived just a moment later.","TWN":"主治醫生說，再慢一步的話，恐怕就沒救了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"이건 응급실 진료비 및 부대비용 영수증입니다. 오늘 중으로 납부하셔야 해요.","JPN":"これは緊急救命室の診療費および付帯費用の領収書です。今日中に納付してください。","ENG":"Here's the bill for the ER and related incidentals. The payment is due today.","TWN":"這是急診室的手術費和其他醫療費用，請在今天內繳清。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"수술도 안 끝났는데 비용부터 청구하는 겁니까?","JPN":"手術が終わってもいないのに費用を請求するのですか？","ENG":"You bill patients even before their surgery is completed?","TWN":"手術都還沒結束就先請款嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"여긴 난민지구 사람들도 많이 오는 곳이야. 치료비 안 내고 도망친 사람이 한둘이어야지.","JPN":"ここは難民地区の人たちがよく来る病院だ。治療費も払わずに逃げた前例が山ほどある。","ENG":"They get a lot of patients from the refugee district here. So they've had their fair share of folks who bailed without paying their bills.","TWN":"因為很多難民都會來這裡看醫生，很多人都沒繳費就落跑。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들은 자기들이 만든 돈에 왜 그렇게 추잡하게 구는지 모르겠군요.","JPN":"ヒューマンたちは自分たちが作った金のことになると、なぜそこまでみっともなくなるのか理解できませんね。","ENG":"It puzzles me how humans obsess so much over their own invention called money.","TWN":"人類在自己創造的金錢面前，怎麼會那麼醜陋呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"목돈 없습니까, 휴먼. 갚을 때 이자는 넉넉하게 챙겨 드리겠습니다.","JPN":"まとまった金はありませんか、ヒューマン。返す時はしっかり利子をつけて返済しますので。","ENG":"Do you have any lump sum funds at your disposal, human? I will be sure to repay you with copious interest.","TWN":"人類，你有錢嗎，你先借我，我利息算高一點給你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"사채업자라더니 병원비 낼 돈도 없나.","JPN":"闇金業者なのに治療費分の金もないのか。","ENG":"What kind of a loan shark can't even afford a hospital bill?","TWN":"不是放高利貸的嗎？怎麼連付醫藥費的錢都沒有？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴업한 지 좀 오래됐습니다.","JPN":"休業してからだいぶ経ちましたから。","ENG":"It's been a while since I've opened up the shop.","TWN":"因為公司已經停業很長一段時間。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"주머니가 궁한 건 나도 마찬가지야. 가게 대신 맡아 주는 걸로 얼마나 벌겠어.","JPN":"懐事情が厳しいのはこっちも一緒だ。コンビニの仕事なんぞ全然稼げないからな。","ENG":"I'm pretty broke myself. Looking after a store like that doesn't exactly pay so well.","TWN":"我的手頭也滿緊的，看個店是能賺多少錢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"……보호자 분들, 난민지구에서 오신 거죠?","JPN":"……保護者の方々、難民地区から来たんですね？","ENG":"…You folks are from the refugee district, aren't you?","TWN":"……你們是保護人吧？是從難民區來的嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"미리 말씀드리는데 나중이라는 거 없어요. 병원장님이 엄청 강경하시거든요.","JPN":"先に申し上げておきますが、後払いは受け付けておりません。院長は支払いには厳しい方でして。","ENG":"Just so you know, you have to pay up front here. No exceptions. The hospital director is very stern about it.","TWN":"醜話先說在前頭，我們不接受下次再付，院長可是很堅持的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그거 꼭 보호자가 아니라도 낼 수 있는 거죠?","JPN":"それは保護者じゃなくても払えるんですよね？","ENG":"He's not so strict about who pays the bill though, right?","TWN":"不是保護人也可以繳費吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"네? 방금 뭐라고 하셨죠?","JPN":"はい？　今、なんとおしゃいましたか？","ENG":"Excuse me? Come again?","TWN":"嗯？你說什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"급한 환자인 것 같은데, 우리 동생이 도와 주고 싶어해서요. 마침 의뢰 수당도 넉넉하게 챙겼거든요.","JPN":"救急患者のようですが、うちの妹が助けてあげたいらしくて。ちょうど依頼費も多めにもらいましたので。","ENG":"We heard what's going on, and little sister here wanted to help out. It just so happens we got a really fat paycheck today.","TWN":"我看她好像情況很緊急，所以我妹妹想做件好事，又剛好收到一筆不錯的委託費用。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"동생……? 누가?","JPN":"妹……？　誰が？","ENG":"Little sister…? Who?","TWN":"妹妹…？誰是妹妹？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"크흠. 너 말이야. 너.","JPN":"コホン。あんたのことよ。","ENG":"Ahem. It's you. Duh.","TWN":"哈哈，當然是你囉，你就是妹妹。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"영수증 주세요. 이래 봬도 정규 태스크포스 소속이니까, 떼어먹힐 걱정은 마시고.","JPN":"領収書もお願いします。こう見えても正規タスクフォースカンパニー所属ですから、ご心配なく。","ENG":"You can hand us the bill instead. Don't worry, we won't bail on you. We actually belong to a fully registered TASKFORCE, okay?","TWN":"收據給我吧，不要看我們這樣，我們可是正當的特遣勢力，不會賴帳的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"아, 네. 그래 주신다면야……","JPN":"あ、はい。払っていただけるなら……","ENG":"Uh… Okay. That will work…","TWN":"喔，好吧，既然你那麼說……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……저 직원, 대화 중에 계속 절 힐끔거리더군요. 제 프레임에 뭐가 묻어 있습니까?","JPN":"……あの職員、会話中にずっと私のほうをちらちら見ていました。私のフレームに何か付いていますか？","ENG":"…That employee kept peeking at me during our exchange. Have I got something on my frame?","TWN":"……那個人，說話的時候眼睛一直在偷瞄我。我的軀殼有沾到什麼東西嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"글쎄, 그보다는 도와 준 사람한테 고마워하는 게 우선 아닌가?","JPN":"さあな、それよりも助けてくれた人にお礼を言うのが先なんじゃないか？","ENG":"I don't know, but maybe thanking our benefactors is first in order?","TWN":"誰知道，這重要嗎？應該先謝謝幫忙的人吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"감사 인사는 됐어. 우리도 지시 받고 온 입장이거든.","JPN":"感謝の言葉はいいわ。私たちも指示を受けてきた立場だからね。","ENG":"Oh, don't worry about it. We're actually here under orders.","TWN":"不用謝，我們也是受人所託。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"코핀 컴퍼니 에디 소대장, 제시카 그린이야.","JPN":"コフィンカンパニー、エディー小隊長のジェシカ・グリーンよ。","ENG":"Jessica Green. Commander of Eddie Squad at the Coffin Company.","TWN":"科芬公司 艾迪小隊長，潔西卡．格林。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"잠깐 우리랑 얘기 좀 할까, 사채업자 씨.","JPN":"ちょっとお時間いいかしら、闇金業者さん。","ENG":"May we have a word with you, loan shark lady?","TWN":"放高利貸的，我們談一下吧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};